import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Dumbbell, Calendar, Activity, Settings, CheckCircle2, Circle, 
  Plus, Minus, Save, ChevronDown, ChevronUp, ChevronRight, ChevronLeft,
  BarChart3, Flame, Clock, 
  Camera, PersonStanding, Edit3, X, ArrowLeft, Download, Upload, Zap, FileText, Trash2,
  TrendingUp, LayoutDashboard, Info, Repeat, AlertTriangle, FileDown, Timer
} from 'lucide-react';

// --- 辅助函数 ---
const getLocalDateString = () => {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const getMonthString = (dateStr) => {
    return dateStr.substring(0, 7); // "2023-11"
};

const superParse = (data, fallback) => {
    if (data === null || data === undefined) return fallback;
    if (typeof data === 'object' || typeof data === 'number') return data;
    try {
        let parsed = JSON.parse(data);
        if (typeof parsed === 'string') return superParse(parsed, fallback);
        return parsed === null ? fallback : parsed;
    } catch (e) { return fallback; }
};

const parseIndex = (val) => {
    const parsed = superParse(val, 0);
    const num = Number(parsed);
    return isNaN(num) ? 0 : num;
};

// --- 核心数据配置 ---
const DAILY_WARMUP = [
  { id: 'wu-1', category: '🔥 每日激活', name: '右侧开放呼吸', sets: 2, defaultReps: '8', unit: 'reps_only', target: '核心/呼吸', description: '【准备】 盘腿坐或坐在凳子上。左手叉腰，右手高举向左上方伸展，上半身向左弯。\n【执行】 用鼻子深吸气，意念集中在右侧腰部，像吹气球一样把右侧凹陷的肋骨“撑开”。呼气时保持肋骨撑开的感觉。\n【目的】 物理拉开右侧被挤压的关节。' },
  { id: 'wu-2', category: '🔥 每日激活', name: '死虫式', sets: 2, defaultReps: '10', unit: 'reps_only', target: '核心/腹肌', description: '【准备】 仰卧，双手举向天花板，膝盖弯曲90度抬起。\n【关键】 腰部死死压住地面，想象腰下压着一张百元大钞，谁都抽不走。\n【执行】 吸气，左手向头顶延伸，右腿伸直（不着地）；呼气还原。换边。\n【禁忌】 如果腰拱起来了，立刻停止，那是无效的。' },
  { id: 'wu-3', category: '🔥 每日激活', name: '臀桥', sets: 1, defaultReps: '15', unit: 'reps_only', target: '臀部', description: '【准备】 仰卧，双脚踩地，与髋同宽。\n【执行】 用脚后跟蹬地，把臀部抬离地面，直到大腿和身体成一条直线。顶峰夹紧屁股1秒，慢慢落下。\n【目的】 唤醒臀肌，防止腰椎代偿。' }
];
const DAILY_REHAB = [
  { id: 'rh-1', category: '🧘 脊柱矫正', name: '左侧平板支撑', sets: 3, defaultReps: '力竭', unit: 'time', target: '核心/左侧腰', description: '【执行】 侧卧，用左手肘和左脚侧面支撑身体。身体成一条直线。\n【核心意念】 想象左侧腰部有一团火在烧，强迫松弛的左侧肌肉收缩，把凸向左边的脊柱顶回中线。\n🚫 右侧严禁做！' },
  { id: 'rh-2', category: '🧘 脊柱矫正', name: '侧卧悬空抬腿', sets: 2, defaultReps: '15', unit: 'reps_only', target: '臀部/右侧腰', description: '【执行】 左侧卧 (凸侧贴地)。左腰下垫个小毛巾卷。右手扶地。\n【动作】 将右腿直直地向上抬起，尽量抬高。抬起时，感受右侧腰部被拉开的空间。\n【目的】 强化凹陷侧（右侧）的张开能力。' }
];
const DAILY_CARDIO = [
  { id: 'cd-1', category: '🏃 减脂有氧', name: '跑步机爬坡', sets: 1, defaultReps: '40', unit: 'time', target: '心肺/腿部', description: '【设置】 坡度 12 | 速度 3.5 - 4.5 | 时间 40 分钟\n【执行铁律】 双手必须离开扶手！\n【原因】 只有不扶扶手，你的核心肌群（腹肌、背肌）才会被迫持续工作来维持身体平衡。扶着做40分钟等于白做一半。' }
];

const MAIN_PLANS_DEFAULT = [
  { id: 'day-A', name: 'Day A: 上肢推', exercises: [...DAILY_WARMUP, { id: 'a-1', category: '🏋️ 力量主课', name: '史密斯平地卧推', sets: 4, defaultReps: '10', unit: 'weight_reps', target: '胸部', description: '【准备】 躺在平凳上，双眼位于杠铃正下方。双手握距比肩宽。\n【执行】 沉肩锁背（肩胛骨后缩钉在凳子上）。吸气下放，杠铃触碰到两乳头连线中点；呼气推起。推起时肘关节不要锁死。\n【注意】 不要耸肩，不要把头抬起来。' }, { id: 'a-2', category: '🏋️ 力量主课', name: '史密斯上斜卧推', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '上胸', description: '【准备】 卧推凳调至 30度 上斜。杠铃落点对准锁骨下方。\n【执行】 同样沉肩，慢下快上。感受上胸肌群的拉伸和收缩。\n【目的】 填补锁骨下方的空缺。' }, { id: 'a-3', category: '🏋️ 力量主课', name: '龙门架低位夹胸', sets: 4, defaultReps: '12', unit: 'weight_reps', target: '胸部/中缝', description: '【准备】 滑轮调至最底端。双手握住D型把手，掌心向前。向前跨一步弓步站立。\n【执行】 保持挺胸抬头！手臂微屈，从下往上、向身体中线提拉，手的高度大概在下巴位置。顶峰用力挤压胸肌上部。\n【康复点】 这个动作强迫你打开胸廓，改善含胸。' }, { id: 'a-4', category: '🏋️ 力量主课', name: '[单臂] 绳索侧平举', sets: 4, defaultReps: '15', unit: 'weight_reps', target: '肩部', description: '【准备】 龙门架滑轮调至低位。左手抓立柱，身体向左微微倾斜，右手持把手。\n【执行】 肘部微屈，用肩膀中束的力量把绳索向侧面举起，直到与肩同高。慢慢下放。\n【要点】 哑铃/手柄不要举得比肘关节高（像倒水一样）。' }, { id: 'a-5', category: '🏋️ 力量主课', name: '帕拉夫推 (Pallof Press)', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '核心抗旋', description: '【准备】 滑轮调至胸口高度。侧对龙门架站立。双手合握把手放在胸口。\n【执行】 吸气，双手用力向正前方推出，伸直手臂。保持3秒纹丝不动，对抗绳索把你拉歪的力量。呼气收回。\n【康复点】 建立脊柱的“水泥柱”稳定性。两侧都要做！' }, { id: 'a-6', category: '🏋️ 力量主课', name: '绳索三头肌下压', sets: 3, defaultReps: '15', unit: 'weight_reps', target: '三头肌', description: '【准备】 高位滑轮，直杆或V把。双脚与肩同宽。\n【执行】 大臂夹紧身体两侧肋骨，绝对不动。只以前臂为半径向下压，直到手臂伸直。顶峰收缩三头肌。\n【错误】 不要用身体重量去压，也不要耸肩。' }, { id: 'pa-1', category: '🥜 花生球松解', name: '胸椎滚动', sets: 1, defaultReps: '90', unit: 'time', target: '背部/胸椎', description: '仰卧，花生球放在两肩胛骨中间。抱头，屁股抬起，用脚蹬地上下滚动。只滚胸椎，别滚腰。' }, { id: 'pa-2', category: '🥜 花生球松解', name: '胸小肌按压', sets: 1, defaultReps: '90', unit: 'time', target: '胸部', description: '靠墙站立。把花生球压在锁骨下方的胸肌外侧，按压酸痛点。' }, ...DAILY_REHAB, ...DAILY_CARDIO] },
  { id: 'day-B', name: 'Day B: 上肢拉', exercises: [...DAILY_WARMUP, { id: 'b-1', category: '🏋️ 力量主课', name: '[单臂] 跪姿高位下拉', sets: 4, defaultReps: '12', unit: 'weight_reps', target: '背部/核心', description: '【左手拉 (练肉)】 单膝跪地。用力向下拉，意念集中在挤压左侧背部，想象要把凸出来的骨头挤回去。\n【右手拉 (拉伸)】 单膝跪地。下拉正常做，但还原回去时要非常慢 (3-4秒)，感受重量把缩短的右腰慢慢拉长、打开。' }, { id: 'b-2', category: '🏋️ 力量主课', name: '[双手] 窄距对握下拉', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '背部', description: '【准备】 换V型把手。\n【执行】 挺胸，身体稍微后倾。将把手拉至上胸部。肩胛骨主动下沉后缩。\n【注意】 身体保持绝对正中，照镜子看自己有没有歪。' }, { id: 'b-3', category: '🏋️ 力量主课', name: '绳索对握划船', sets: 4, defaultReps: '12', unit: 'weight_reps', target: '背部', description: '【准备】 坐姿（地上或凳子），双脚踩稳。使用V把。\n【执行】 先沉肩，再屈肘将手柄拉向肚脐。在动作终点，用力夹紧背后的肩胛骨。' }, { id: 'b-4', category: '🏋️ 力量主课', name: '绳索面拉 (Face Pull)', sets: 4, defaultReps: '15', unit: 'weight_reps', target: '后肩/肩袖', description: '【准备】 滑轮调至高位，使用绳索头。\n【执行】 双手拉住绳索两头，拉向额头方向。动作终点时，大拇指指向后方，形成一个投降的姿势。\n【目的】 强化肩袖肌群，改善圆肩。' }, { id: 'b-5', category: '🏋️ 力量主课', name: '龙门架二头弯举', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '二头肌', description: '【准备】 低位滑轮，直杆或曲杆。站姿。\n【执行】 大臂固定在身体两侧。弯举起前臂，挤压二头肌。\n【注意】 身体不要前后晃动借力。' }, { id: 'b-6', category: '🏋️ 力量主课', name: '跪姿绳索伐木', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '腹外斜肌', description: '【准备】 滑轮调至高位。侧对龙门架，单膝跪地（靠近机器的腿跪地）。双手握住绳索。\n【执行】 像砍树一样，从斜上方拉向斜下方（对侧胯部）。只转动胸廓，腰椎不要过度扭转。\n【目的】 强化腹外斜肌，增强核心抗旋能力。' }, { id: 'pb-1', category: '🥜 花生球松解', name: '右侧竖脊肌按压', sets: 1, defaultReps: '90', unit: 'time', target: '下背部', description: '靠墙站立。把球放在右侧背部最紧的地方（避开骨头）。利用体重轻轻按压。' }, { id: 'pb-2', category: '🥜 花生球松解', name: '右侧腋下(背阔肌)按压', sets: 1, defaultReps: '60', unit: 'time', target: '背部', description: '侧躺，把花生球放在右侧腋下后方（大圆肌/背阔肌交界处）。这里会很痛，忍住按压 60 秒，把粘连揉开。' }, ...DAILY_REHAB, ...DAILY_CARDIO] },
  { id: 'day-C', name: 'Day C: 下肢', exercises: [...DAILY_WARMUP, { id: 'c-1', category: '🏋️ 力量主课', name: '史密斯臀推', sets: 5, defaultReps: '12', unit: 'weight_reps', target: '臀部', description: '【准备】 背靠卧推凳，肩胛骨下沿卡在凳子边缘。杠铃杆加护垫，放在髋关节折痕处。\n【执行】 下巴收紧看膝盖。臀部发力向上顶，直到身体水平。在最高点用力夹紧屁股停顿1秒。缓慢下放。\n【注意】 腰不要反弓，是用屁股顶，不是用腰顶。' }, { id: 'c-2', category: '🏋️ 力量主课', name: '[扶杆] 保加利亚蹲', sets: 3, defaultReps: '10', unit: 'weight_reps', target: '腿部/臀部', description: '【准备】 后脚脚背搭在凳子上。必须扶杆保持平衡。\n【执行】 直上直下蹲。前腿膝盖不要过度超过脚尖。蹲到大腿与地面平行。\n【康复点】 保证骨盆水平如水面，不要一边高一边低。' }, { id: 'c-3', category: '🏋️ 力量主课', name: '绳索胯下臀拉', sets: 3, defaultReps: '15', unit: 'weight_reps', target: '臀部/腘绳肌', description: '【准备】 背对龙门架，低位滑轮，使用绳索头。绳索从两腿之间穿过。\n【执行】 双手握绳，屁股向后撅（屈髋），上半身前倾，膝盖微屈。大腿后侧有拉伸感。然后臀部发力向前顶，站直身体。\n【注意】 这是一个“折叠髋部”的动作，不是深蹲。' }, { id: 'c-4', category: '🏋️ 力量主课', name: '站姿单腿勾腿', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '腘绳肌', description: '【准备】 带上脚踝扣。面对龙门架，手扶立柱。大腿贴紧固定不动。\n【执行】 小腿向后勾起，试图用脚后跟踢屁股。感受大腿后侧肌肉收缩。\n【注意】 腰不要动，只动膝关节。' }, { id: 'c-5', category: '🏋️ 力量主课', name: '绳索腿外展', sets: 3, defaultReps: '15', unit: 'weight_reps', target: '臀中肌', description: '【准备】 带上脚踝扣。侧对龙门架。手扶立柱。\n【执行】 外侧腿向正侧方抬起约 30-45 度。感受屁股侧面上方（臀中肌）发力。\n【注意】 身体不要向反方向倾斜代偿。' }, { id: 'c-6', category: '🏋️ 力量主课', name: '绳索腿内收', sets: 2, defaultReps: '15', unit: 'weight_reps', target: '内收肌', description: '【准备】 带上脚踝扣。侧对龙门架，但这回是练靠近机器的那条腿。\n【执行】 腿从外向内扫，扫过身体中线，像踢足球传球一样。\n【目的】 收紧大腿内侧松弛的肌肉。' }, { id: 'pc-1', category: '🥜 花生球松解', name: '臀中肌按压', sets: 1, defaultReps: '30', unit: 'time', target: '臀部', description: '【执行】 坐在地上，身体倾斜，把球压在屁股侧面最酸痛的一个点（臀中肌）。保持不动 30 秒。' }, { id: 'pc-2', category: '🥜 花生球松解', name: '足底筋膜滚动', sets: 1, defaultReps: '60', unit: 'time', target: '足部', description: '【执行】 站起来踩着花生球滚脚底，从脚跟滚到脚趾。' }, ...DAILY_REHAB, ...DAILY_CARDIO] },
  { id: 'day-D', name: 'Day D: 手臂 + 小腿', exercises: [...DAILY_WARMUP, { id: 'd-1', category: '🏋️ 力量主课', name: '绳索交叉侧平举', sets: 4, defaultReps: '15', unit: 'weight_reps', target: '肩部', description: '【准备】 双滑轮低位。左手抓右边绳索，右手抓左边绳索（交叉）。\n【执行】 向身体两侧拉起，直到手臂与地面平行。\n【注意】 全程控制，不要用爆发力甩上去。' }, { id: 'd-2', category: '🏋️ 力量主课', name: '超级组A: 绳索过顶臂屈伸', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '三头肌', description: '【准备】 低位滑轮，绳索头。前后分腿站立（极其重要，保护腰椎）。\n【执行】 双手抓绳索举过头顶。大臂贴近耳朵不动，屈肘将绳索放至脑后，再伸直手臂。' }, { id: 'd-3', category: '🏋️ 力量主课', name: '超级组A: 绳索锤式弯举', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '二头肌/肱肌', description: '【准备】 紧接着做，不休息。低位滑轮，绳索头。\n【执行】 掌心相对（像握锤子），大臂不动，弯举起绳索。\n【目的】 锻炼肱肌，让手臂外侧线条好看。' }, { id: 'd-4', category: '🏋️ 力量主课', name: '超级组B: 绳索三头下压', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '三头肌', description: '【准备】 高位滑轮，V把。\n【执行】 常规下压，动作标准同 Day A。' }, { id: 'd-5', category: '🏋️ 力量主课', name: '超级组B: 绳索常规弯举', sets: 3, defaultReps: '12', unit: 'weight_reps', target: '二头肌', description: '【准备】 紧接着做，不休息。低位滑轮，直杆。\n【执行】 掌心朝上弯举。' }, { id: 'd-6', category: '🏋️ 力量主课', name: '俯身飞鸟', sets: 3, defaultReps: '15', unit: 'weight_reps', target: '后肩', description: '【准备】 双手持小哑铃。屈髋俯身，背部挺直。\n【执行】 像大鹏展翅一样向身体两侧抬起手臂，感受后背肩膀（三角肌后束）发力。' }, { id: 'd-7', category: '🏋️ 力量主课', name: '史密斯坐姿提踵', sets: 4, defaultReps: '20', unit: 'weight_reps', target: '小腿', description: '【准备】 坐在平凳端头。大腿膝盖上方垫好护垫（或毛巾），顶住杠铃杆。脚尖踩在踏板/杠铃片上。\n【执行】 踮起脚尖，尽量高；落下脚后跟，尽量低。\n【目的】 锻炼小腿，增加平衡能力。' }, { id: 'pd-1', category: '🥜 花生球松解', name: '上斜方肌按压', sets: 1, defaultReps: '60', unit: 'time', target: '肩颈', description: '【执行】 靠墙站。球压在肩膀肉最厚的地方。身体后仰。缓解练肩后的颈部紧张。' }, { id: 'pd-2', category: '🥜 花生球松解', name: '小腿肚放松', sets: 1, defaultReps: '60', unit: 'time', target: '小腿', description: '【执行】 坐在地上，把小腿肚架在花生球凹槽里，左右摆动放松。' }, ...DAILY_REHAB, ...DAILY_CARDIO] }
];

// --- 🔥 极简图表组件 ---
const SimpleLineChart = ({ data, color = "#f97316", height = 150, suffix="", title }) => {
  if (!data || data.length < 2) return (
    <div className="flex flex-col items-center justify-center text-slate-400 text-xs bg-slate-50 dark:bg-slate-900 rounded-2xl border border-dashed border-slate-200 dark:border-slate-700" style={{height: `${height}px`}}>
      <BarChart3 size={24} className="mb-2 opacity-20"/>
      <span>暂无足够数据</span>
    </div>
  );

  const maxVal = Math.max(...data.map(d => d.value));
  const minVal = Math.min(...data.map(d => d.value)) * 0.9; 
  const range = maxVal - minVal || 1;

  // 坐标点计算 (0-100)
  const points = data.map((d, i) => {
    const x = (i / (data.length - 1)) * 100;
    const y = 100 - ((d.value - minVal) / range) * 100; 
    return { x, y, ...d };
  });

  const linePath = points.map((p, i) => `${i===0?'M':'L'} ${p.x},${p.y}`).join(' ');
  const areaPath = `${linePath} L ${points[points.length-1].x},100 L ${points[0].x},100 Z`;

  return (
    <div className="w-full relative group select-none" style={{ height: `${height}px` }}>
      <div className="absolute top-0 right-0 text-xs font-bold bg-white/80 backdrop-blur px-2 py-1 rounded text-slate-600 border border-slate-100 shadow-sm z-10">
        {title && <span className="text-[10px] text-slate-400 mr-1 block">{title}</span>}
        <span style={{color}}>{Math.round(data[data.length-1].value * 10) / 10}</span> <span className="text-[10px] text-slate-400">{suffix}</span>
      </div>
      <div className="absolute inset-0 p-4 flex items-end">
          <div className="relative w-full h-full">
              <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none" className="absolute inset-0 overflow-visible">
                <defs>
                    <linearGradient id={`grad-simple-${color.replace('#','')}`} x1="0%" y1="0%" x2="0%" y2="100%">
                        <stop offset="0%" stopColor={color} stopOpacity="0.15" />
                        <stop offset="100%" stopColor={color} stopOpacity="0" />
                    </linearGradient>
                </defs>
                <path d={areaPath} fill={`url(#grad-simple-${color.replace('#','')})`} />
                <path d={linePath} fill="none" stroke={color} strokeWidth="2" vectorEffect="non-scaling-stroke" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
              {points.map((p, i) => (
                  <div 
                    key={i}
                    className="absolute w-2.5 h-2.5 rounded-full bg-white border-2 transition-transform duration-300 group-hover:scale-125 shadow-sm"
                    style={{
                        left: `${p.x}%`,
                        top: `${p.y}%`,
                        borderColor: color,
                        transform: 'translate(-50%, -50%)'
                    }}
                  />
              ))}
          </div>
      </div>
      <div className="absolute bottom-0 left-0 right-0 flex justify-between text-[9px] text-slate-400 px-4 font-mono opacity-60">
        <span>{data[0].date}</span>
        <span>{data[data.length - 1].date}</span>
      </div>
    </div>
  );
};

// 🔥 升级版 SmartInput：支持禁用状态
const SmartInput = ({ value, onChange, placeholder, step = 1, label, disabled }) => {
  // 如果禁用，渲染为不可交互的灰色块
  if (disabled) {
      return (
        <div className="flex-1 flex flex-col items-center group opacity-50 pointer-events-none">
            <div className="flex items-center w-full">
                <div className="w-full bg-slate-50 border-y border-slate-100 h-10 flex items-center justify-center text-slate-300 font-bold select-none text-sm rounded-xl">
                    -
                </div>
            </div>
            {label && <span className="text-[10px] text-slate-300 mt-1 font-medium">{label}</span>}
        </div>
      );
  }

  const handleAdjust = (delta) => {
    const current = parseFloat(value) || 0;
    const next = Math.max(0, current + delta);
    onChange(Number.isInteger(next) ? next.toString() : next.toFixed(2).replace(/\.00$/, '').replace(/(\.\d)0$/, '$1'));
  };

  return (
    <div className="flex-1 flex flex-col items-center relative group">
      <div className="flex items-center w-full">
        <button onClick={() => handleAdjust(-step)} className="w-9 h-10 bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-l-xl flex items-center justify-center transition-colors active:scale-95"><Minus size={16} /></button>
        <input type="number" placeholder={placeholder} value={value} onChange={(e) => onChange(e.target.value)} className="w-full bg-slate-50 border-y border-slate-200 h-10 text-center font-bold outline-none text-slate-800 text-base z-10 focus:bg-white focus:border-orange-200 transition-colors" />
        <button onClick={() => handleAdjust(step)} className="w-9 h-10 bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-r-xl flex items-center justify-center transition-colors active:scale-95"><Plus size={16} /></button>
      </div>
      {label && <span className="text-[10px] text-slate-400 mt-1 font-medium">{label}</span>}
    </div>
  );
};

