const CalendarHeatmap = ({ history, onSelectDate }) => {
  const [viewDate, setViewDate] = useState(new Date());
  const [selected, setSelected] = useState(null);

  const changeMonth = (delta) => {
    const newDate = new Date(viewDate);
    newDate.setMonth(newDate.getMonth() + delta);
    setViewDate(newDate);
  };

  const calendarDays = useMemo(() => {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const workMap = {};
    history.forEach(h => {
      if (h.type === 'workout') workMap[h.date] = 'workout';
      else if (h.type === 'rest') workMap[h.date] = 'rest';
    });

    const days = [];
    for (let i = 0; i < firstDay; i++) days.push({ type: 'empty', key: `empty-${i}` });
    for (let i = 1; i <= daysInMonth; i++) {
      const monthStr = String(month + 1).padStart(2, '0');
      const dayStr = String(i).padStart(2, '0');
      const dateStr = `${year}-${monthStr}-${dayStr}`;
      days.push({
        type: 'day', key: dateStr, dayNum: i, status: workMap[dateStr] || 'none', isToday: dateStr === getLocalDateString()
      });
    }
    return days;
  }, [viewDate, history]);

  const monthLabel = viewDate.toLocaleString('zh-CN', { year: 'numeric', month: 'long' });

  return (
    <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700">
      <div className="flex items-center justify-between mb-4">
        <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full text-slate-400"><ChevronLeft size={20}/></button>
        <h3 className="font-bold text-slate-700 dark:text-slate-200 flex items-center gap-2">{monthLabel}</h3>
        <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full text-slate-400"><ChevronRight size={20}/></button>
      </div>
      <div className="grid grid-cols-7 gap-2">
        {['日','一','二','三','四','五','六'].map(d => <div key={d} className="text-center text-[10px] text-slate-400 mb-1 font-bold">{d}</div>)}
        {calendarDays.map((day) => {
          if (day.type === 'empty') return <div key={day.key} className="aspect-square"></div>;
          const isSelected = day.key === selected;
          return (
            <div key={day.key} 
                onClick={() => {
                   const newSel = isSelected ? null : day.key;
                   setSelected(newSel);
                   onSelectDate(newSel);
                }}
                className={`
                aspect-square rounded-lg flex items-center justify-center text-[10px] font-bold relative transition-all cursor-pointer
                ${day.status === 'workout' ? 'bg-orange-500 text-white' : day.status === 'rest' ? 'bg-blue-100 text-blue-500' : 'bg-slate-50 text-slate-400 dark:bg-slate-700 dark:text-slate-500'} 
                ${day.isToday ? 'ring-2 ring-slate-800 dark:ring-white ring-offset-1' : ''}
                ${isSelected ? 'ring-4 ring-orange-200 dark:ring-orange-900/50 scale-110 z-10' : ''}
            `}>
              {day.dayNum}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default function App() {
  const [activeTab, setActiveTab] = useState('home');
  const [plans, setPlans] = useState(MAIN_PLANS_DEFAULT);
  const [currentPlanIndex, setCurrentPlanIndex] = useState(0);
  const [history, setHistory] = useState([]);
  const [exerciseHistory, setExerciseHistory] = useState({});
  const [bodyStats, setBodyStats] = useState([]);
  const [activeWorkout, setActiveWorkout] = useState(null);
  const [workoutLogs, setWorkoutLogs] = useState({});
  const [expandedExId, setExpandedExId] = useState(null);
  const [showSummaryModal, setShowSummaryModal] = useState(false);
  const [summaryData, setSummaryData] = useState({ activeCalories: '', avgHeartRate: '', rpe: 5, note: '', weight: '' });
  const [editingPlanId, setEditingPlanId] = useState(null);

  // 🔥 新增：训练开始时间
  const [workoutStartTime, setWorkoutStartTime] = useState(null);
  // 🔥 新增：实时计时器 (用于显示)
  const [elapsedSeconds, setElapsedSeconds] = useState(0);

  const [detailChartType, setDetailChartType] = useState(null); 
  const [selectedExerciseForChart, setSelectedExerciseForChart] = useState(null);
  const [chartTimeRange, setChartTimeRange] = useState('recent'); 

  const [showPlanSelector, setShowPlanSelector] = useState(false);
  const [deleteConfirmItem, setDeleteConfirmItem] = useState(null);

  const [selectedDate, setSelectedDate] = useState(null); 
  const fileRef = useRef(null);

  // Analytics
  const volumeDataRecent = useMemo(() => history.filter(h => h.type === 'workout' && h.metrics?.volume > 0).slice(0, 15).reverse().map(h => ({ date: h.date.slice(5), value: h.metrics.volume, timestamp: h.timestamp })), [history]);
  const weightDataRecent = useMemo(() => bodyStats.filter(s => s.weight).slice(0, 15).reverse().map(s => ({ date: s.date.slice(5), value: parseFloat(s.weight), timestamp: s.timestamp })), [bodyStats]);
  const daysTrained = useMemo(() => new Set(history.filter(h => h.type === 'workout').map(h => h.date)).size, [history]);

  // 🔥 Analytics: 训练时长统计
  const totalDurationMinutes = useMemo(() => history.filter(h => h.type === 'workout').reduce((acc, curr) => acc + (curr.metrics?.duration || 0), 0), [history]);
  const avgDurationMinutes = useMemo(() => daysTrained > 0 ? Math.round(totalDurationMinutes / daysTrained) : 0, [totalDurationMinutes, daysTrained]);

  const getMonthlyData = (sourceData, valueKey) => {
      const map = new Map();
      sourceData.forEach(item => {
          const m = getMonthString(item.date);
          if (!map.has(m)) map.set(m, { sum: 0, count: 0 });
          const entry = map.get(m);
          const val = valueKey === 'volume' ? (item.metrics?.volume || 0) : parseFloat(item.weight);
          if (val > 0) {
            entry.sum += val;
            entry.count += 1;
          }
      });
      return Array.from(map.entries())
        .sort((a,b) => a[0].localeCompare(b[0]))
        .map(([date, data]) => ({
          date, 
          value: valueKey === 'volume' ? Math.round(data.sum) : parseFloat((data.sum / data.count).toFixed(1)) 
        }));
  };

  const volumeDataMonth = useMemo(() => getMonthlyData(history.filter(h => h.type === 'workout'), 'volume'), [history]);
  const weightDataMonth = useMemo(() => getMonthlyData(bodyStats, 'weight'), [bodyStats]);

  const findExerciseName = (id) => {
      for (const p of plans) {
          const found = p.exercises.find(e => e.id === id);
          if (found) return found.name;
      }
      return '未知动作';
  };

  const allHistoryExercises = useMemo(() => {
      const map = new Map();
      plans.forEach(p => p.exercises.forEach(e => map.set(e.id, e.name)));
      return Array.from(map.entries()).map(([id, name]) => ({ id, name }));
  }, [plans]);

  const getExerciseProgressData = (exId) => {
      const data = [];
      [...history].reverse().forEach(h => {
          if (h.type === 'workout' && h.logs && h.logs[exId]) {
              const validSets = h.logs[exId].filter(s => s.completed && parseFloat(s.weight) > 0);
              if (validSets.length > 0) {
                  const maxW = Math.max(...validSets.map(s => parseFloat(s.weight)));
                  data.push({ date: h.date.slice(5), value: maxW });
              }
          }
      });
      return data;
  };

  // 🔥 计时器 Effect
  useEffect(() => {
      let interval;
      if (activeWorkout && workoutStartTime) {
          interval = setInterval(() => {
              const now = Date.now();
              setElapsedSeconds(Math.floor((now - workoutStartTime) / 1000));
          }, 1000);
      } else {
          setElapsedSeconds(0);
      }
      return () => clearInterval(interval);
  }, [activeWorkout, workoutStartTime]);

  // 格式化时间 mm:ss
  const formatTime = (totalSeconds) => {
      const m = Math.floor(totalSeconds / 60).toString().padStart(2, '0');
      const s = (totalSeconds % 60).toString().padStart(2, '0');
      return `${m}:${s}`;
  };

  useEffect(() => {
    const load = (key, setter) => { 
        const data = localStorage.getItem(key); 
        if (data) {
            let parsed = superParse(data, []);
            if (key === 'fitness_history_v6' && Array.isArray(parsed)) {
                parsed = parsed.map((item, index) => {
                    if (!item.timestamp) return { ...item, timestamp: Date.now() - (index * 1000) };
                    return item;
                });
                localStorage.setItem(key, JSON.stringify(parsed));
            }
            if (key === 'fitness_stats_v6' && Array.isArray(parsed)) {
                parsed = parsed.map((item, index) => {
                    if (!item.timestamp) return { ...item, timestamp: Date.now() - (index * 1000) };
                    return item;
                });
                localStorage.setItem(key, JSON.stringify(parsed));
            }
            setter(parsed);
        }
    };
    const loadObj = (key, setter) => { const data = localStorage.getItem(key); if (data) setter(superParse(data, {})); };
    const loadNum = (key, setter) => { 
        const data = localStorage.getItem(key); 
        if (data) setter(parseIndex(data)); 
    };

    loadNum('fitness_plan_index_v6', setCurrentPlanIndex);
    load('fitness_history_v6', setHistory);
    load('fitness_stats_v6', setBodyStats);
    loadObj('fitness_ex_history_v6', setExerciseHistory);

    const savedPlans = localStorage.getItem('fitness_plans_v6');
    if (savedPlans) {
        const parsedPlans = superParse(savedPlans, null);
        if (parsedPlans) setPlans(parsedPlans);
        else {
            setPlans(MAIN_PLANS_DEFAULT);
            localStorage.setItem('fitness_plans_v6', JSON.stringify(MAIN_PLANS_DEFAULT));
        }
    }
  }, []);

  const saveToLocal = (key, data) => localStorage.setItem(key, JSON.stringify(data));

  const startWorkout = () => {
    let currentPlan = plans[currentPlanIndex];
    if (!currentPlan) {
        if (plans.length > 0) { setCurrentPlanIndex(0); currentPlan = plans[0]; } 
        else { setPlans(MAIN_PLANS_DEFAULT); currentPlan = MAIN_PLANS_DEFAULT[0]; }
    }

    const initialLogs = {};
    if (currentPlan && currentPlan.exercises) {
        currentPlan.exercises.forEach(ex => {
          const lastRecord = exerciseHistory[ex.id];
          initialLogs[ex.id] = Array(ex.sets).fill(null).map(() => ({ weight: lastRecord?.weight || '', reps: '', completed: false }));
        });
    }
    setWorkoutLogs(initialLogs);
    // 🔥 记录开始时间
    setWorkoutStartTime(Date.now());
    setActiveWorkout(currentPlan);
    setActiveTab('workout');
    if(currentPlan && currentPlan.exercises && currentPlan.exercises.length > 0) setExpandedExId(currentPlan.exercises[0].id);
  };

  const updateSet = (exId, idx, field, val) => {
    const newLogs = { ...workoutLogs };
    if (newLogs[exId]) {
        newLogs[exId] = [...newLogs[exId]]; 
        newLogs[exId][idx] = { ...newLogs[exId][idx], [field]: val };
    }
    setWorkoutLogs(newLogs);
  };

  const confirmFinishWorkout = () => {
    if (!summaryData.weight) {
        alert('⚠️ 训练辛苦了！请记录一下今日体重再保存吧~');
        return;
    }

    const date = getLocalDateString();

    // 🔥 计算训练时长 (分钟)
    const endTime = Date.now();
    // 🔥 优化：即使只练了1秒，也算1分钟，避免显示为0
    const durationMinutes = workoutStartTime ? Math.ceil((endTime - workoutStartTime) / 60000) : 0;

    const newStats = [{ date, weight: summaryData.weight, timestamp: Date.now() }, ...bodyStats];
    setBodyStats(newStats);
    saveToLocal('fitness_stats_v6', newStats);

    let totalVolume = 0;
    const newExHistory = { ...exerciseHistory };

    Object.keys(workoutLogs).forEach(exId => {
      const sets = workoutLogs[exId];
      const exDef = activeWorkout.exercises.find(e => e.id === exId);
      let setVol = 0;
      sets.forEach(s => { 
          if (s.completed) {
              const w = parseFloat(s.weight) || 0;
              const r = parseFloat(s.reps) || 0;

              if (exDef && exDef.unit === 'reps_only') {
                  setVol += r; 
              } else if (exDef && exDef.unit === 'time') {
                  setVol += w;
              } else {
                  if (w > 0 && r > 0) setVol += w * r;
              }
          }
      });
      totalVolume += setVol;
      const lastValidSet = [...sets].reverse().find(s => s.weight && s.completed);
      if (lastValidSet) newExHistory[exId] = { weight: lastValidSet.weight, date };
    });

    const newEntry = { 
        date, 
        timestamp: Date.now(), 
        type: 'workout', 
        planName: activeWorkout.name, 
        logs: workoutLogs, 
        // 🔥 存入 duration
        metrics: { volume: totalVolume, duration: durationMinutes, ...summaryData } 
    };

    const newHistory = [newEntry, ...history];
    setHistory(newHistory); setExerciseHistory(newExHistory);
    saveToLocal('fitness_history_v6', newHistory); saveToLocal('fitness_ex_history_v6', newExHistory);

    const nextIndex = (currentPlanIndex + 1) % plans.length;
    setCurrentPlanIndex(nextIndex); saveToLocal('fitness_plan_index_v6', nextIndex.toString());

    setShowSummaryModal(false); setActiveWorkout(null); setWorkoutLogs({}); setSummaryData({ activeCalories: '', avgHeartRate: '', rpe: 5, note: '', weight: '' }); setActiveTab('home');
    setWorkoutStartTime(null); // 重置时间

    setTimeout(() => {
        exportData(); 
        alert(`🎉 训练完成！耗时 ${durationMinutes} 分钟。数据已自动备份。`);
    }, 500);
  };

  const logRestDay = () => {
    const date = getLocalDateString();
    const newHistory = [{ date, timestamp: Date.now(), type: 'rest', note: '休息日' }, ...history];
    setHistory(newHistory); saveToLocal('fitness_history_v6', newHistory); alert('已记录休息。');
  };

  const executeDelete = () => {
      if (!deleteConfirmItem) return;

      if (deleteConfirmItem.type === 'history') {
          const newHistory = history.filter(h => String(h.timestamp) !== String(deleteConfirmItem.data.timestamp));
          setHistory(newHistory);
          saveToLocal('fitness_history_v6', newHistory);
      } else if (deleteConfirmItem.type === 'weight') {
          const newStats = bodyStats.filter(s => String(s.timestamp) !== String(deleteConfirmItem.data.timestamp));
          setBodyStats(newStats);
          saveToLocal('fitness_stats_v6', newStats);
      }

      setDeleteConfirmItem(null);
  };

  const updatePlans = (newPlans) => { setPlans(newPlans); saveToLocal('fitness_plans_v6', newPlans); };
  const updatePlanName = (pi, v) => { const np = plans.map((p,i)=>i===pi?{...p,name:v}:p); updatePlans(np); };
  const deleteExercise = (pi, eid) => { if(!confirm('删除?')) return; const np = plans.map((p,i)=>i===pi?{...p,exercises:p.exercises.filter(e=>e.id!==eid)}:p); updatePlans(np); };
  const addExercise = (pi) => { const ex={id:`c-${Date.now()}`,category:'🏋️ 新增',name:'新动作',sets:3,defaultReps:'10',unit:'weight_reps',description:'点击编辑'}; const np=plans.map((p,i)=>i===pi?{...p,exercises:[...p.exercises,ex]}:p); updatePlans(np); };
  const updateExercise = (pi, ei, f, v) => { const np=plans.map((p,i)=>i===pi?{...p,exercises:p.exercises.map((e,j)=>j===ei?{...e,[f]:v}:e)}:p); updatePlans(np); };
  const triggerCamera = () => { const i=document.createElement('input'); i.type='file'; i.accept='image/*'; i.capture='environment'; i.onchange=()=>alert('照片已保存到系统相册。'); i.click(); };
  const exportData = () => {
      const d = { history, plans, stats: bodyStats, exHistory: exerciseHistory, planIndex: currentPlanIndex };
      const b = new Blob([JSON.stringify(d)], {type:'application/json'});
      const u = URL.createObjectURL(b);
      const a = document.createElement('a'); a.href=u; a.download=`LaoDaZhuang_${getLocalDateString()}.json`;
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const handleFileImport = (e) => {
      const f = e.target.files[0]; if(!f) return;
      const r = new FileReader();
      r.onload = (ev) => {
          try {
              const d = superParse(ev.target.result, null);
              if(!d) throw new Error("Empty");

              let importedHistory = [];
              let importedPlans = plans;

              if(d.history) { 
                  importedHistory = superParse(d.history, []).map((item, index) => {
                      if (!item.timestamp) return { ...item, timestamp: Date.now() - (index * 1000) };
                      return item;
                  });
                  const val = JSON.stringify(importedHistory);
                  localStorage.setItem('fitness_history_v6', val); 
                  setHistory(importedHistory); 
              }

              if(d.plans) { 
                  const val = JSON.stringify(d.plans);
                  localStorage.setItem('fitness_plans_v6', val); 
                  importedPlans = superParse(d.plans, []);
                  setPlans(importedPlans); 
              }

              if(d.stats) { 
                  const parsedStats = superParse(d.stats, []).map((item, index) => {
                      if (!item.timestamp) return { ...item, timestamp: Date.now() - (index * 1000) };
                      return item;
                  });
                  localStorage.setItem('fitness_stats_v6', JSON.stringify(parsedStats)); 
                  setBodyStats(parsedStats); 
              }
              if(d.exHistory) { localStorage.setItem('fitness_ex_history_v6', JSON.stringify(d.exHistory)); setExerciseHistory(superParse(d.exHistory, {})); }

              if (importedHistory && importedHistory.length > 0) {
                  const lastWorkout = importedHistory.find(h => h.type === 'workout');
                  if (lastWorkout && lastWorkout.planName) {
                      const lastPlanIndex = importedPlans.findIndex(p => p.name === lastWorkout.planName);

                      if (lastPlanIndex !== -1) {
                          const nextIdx = (lastPlanIndex + 1) % importedPlans.length;
                          localStorage.setItem('fitness_plan_index_v6', nextIdx);
                          setCurrentPlanIndex(nextIdx);
                      }
                  }
              }

              alert('✅ 数据恢复成功！计划已自动调整。'); 
              e.target.value = '';
          } catch(err) { console.error(err); alert('❌ 文件无效'); }
      };
      r.readAsText(f);
