                   <p className="text-slate-400 text-xs font-bold mb-1 uppercase tracking-wider">训练时长</p>
                   <p className="text-2xl font-black text-slate-800 flex items-end gap-1">
                       {Math.round(totalDurationMinutes/60)}<span className="text-sm font-medium text-slate-400 mb-1">小时</span>
                   </p>
                   <p className="text-xs text-slate-400 mt-1">平均 {avgDurationMinutes} 分钟/次</p>
               </div>
               <Timer className="absolute -right-2 -bottom-2 text-slate-100" size={64}/>
            </div>
         </div>

         <CalendarHeatmap history={history} onSelectDate={setSelectedDate} />

         {selectedDate ? (
             <div className="animate-in">
                <div className="flex items-center justify-between mb-3">
                    <h3 className="font-bold text-slate-800">{selectedDate} 的记录</h3>
                    <button onClick={() => setSelectedDate(null)} className="text-xs text-slate-400">关闭</button>
                </div>
                {selectedLogs.length > 0 ? (
                    <div className="space-y-3">
                        {selectedLogs.map((h, i) => <HistoryItem key={h.timestamp || i} item={h} onDelete={setDeleteConfirmItem} />)}
                    </div>
                ) : (
                    <div className="text-center py-8 text-slate-400 bg-slate-50 rounded-2xl border border-dashed border-slate-200">这一天没有记录哦</div>
                )}
             </div>
         ) : (
             <>
                 <div onClick={() => setDetailChartType('weight')} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow cursor-pointer relative overflow-hidden">
                    <div className="flex items-center gap-3 mb-5"><div className="p-2 bg-blue-50 rounded-full text-blue-500"><PersonStanding size={20}/></div><h3 className="font-bold text-slate-800">体重趋势</h3><ChevronRight className="ml-auto text-slate-300"/></div>
                    <SimpleLineChart data={weightDataRecent} color="#3b82f6" suffix="kg" />
                 </div>
                 <div onClick={() => setDetailChartType('volume')} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow cursor-pointer relative overflow-hidden">
                    <div className="flex items-center gap-3 mb-5">
                        <div className="p-2 bg-orange-50 rounded-full text-orange-500"><Dumbbell size={20}/></div>
                        <div className="flex flex-col">
                            <h3 className="font-bold text-slate-800 flex items-center gap-1">容量趋势 <Info size={12} className="text-slate-400" onClick={(e)=>{e.stopPropagation(); alert('容量 = 重量 x 次数。它反映了你本次训练的总负荷量，用于监控疲劳度。');}}/></h3>
                            <span className="text-[9px] text-slate-400">容量 = 负重 x 次数</span>
                        </div>
                        <ChevronRight className="ml-auto text-slate-300"/>
                    </div>
                    <SimpleLineChart data={volumeDataRecent} color="#f97316" />
                 </div>
                 <div onClick={() => setDetailChartType('exercise')} className="bg-gradient-to-br from-purple-500 to-indigo-600 p-5 rounded-3xl shadow-lg shadow-purple-500/30 cursor-pointer relative overflow-hidden text-white group">
                    <div className="flex items-center justify-between relative z-10">
                        <div className="flex items-center gap-3"><div className="p-2 bg-white/20 rounded-full"><TrendingUp size={20} className="text-white"/></div><h3 className="font-bold text-lg">单动作分析</h3></div>
                        <ChevronRight className="text-purple-200"/>
                    </div>
                    <p className="relative z-10 mt-4 text-purple-100 text-sm font-medium opacity-90">点击查看深蹲、卧推等动作的<br/>力量增长曲线</p>
                    <TrendingUp className="absolute -right-4 -bottom-4 text-white opacity-10 w-32 h-32" />
                 </div>
             </>
         )}

         <div className="bg-slate-900 p-4 rounded-2xl flex gap-3 shadow-xl shadow-slate-900/20">
            {/* 🔥 快速记录体重也加上 timestamp，保持一致 */}
            <input type="number" className="flex-1 p-3 bg-slate-800 rounded-xl text-white font-bold text-center outline-none focus:ring-2 ring-slate-600 transition-all" placeholder="输入今日体重 (kg)" onBlur={e=>{if(e.target.value){const ns=[{date:getLocalDateString(),weight:e.target.value, timestamp: Date.now()},...bodyStats];setBodyStats(ns);saveToLocal('fitness_stats_v6',ns);e.target.value='';}}} />
            <button className="bg-white text-slate-900 px-5 rounded-xl font-black active:scale-95 transition-transform"><Plus size={20}/></button>
         </div>

         {renderDetailChartModal()}
         {renderDeleteModal()}
       </div>
     );
  };

  const renderSettingsView = () => (
      <div className="p-4 pb-28 animate-in safe-top">
          <div className="flex items-center gap-3 mb-8">
             {editingPlanId!==null && <button onClick={()=>setEditingPlanId(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ArrowLeft size={24}/></button>}
             <h2 className="text-3xl font-black text-slate-800">{editingPlanId!==null?'编辑计划':'设置 & 备份'}</h2>
          </div>
          {editingPlanId===null ? (
            <div className="space-y-6">
                <div className="space-y-3">{plans.map((plan, idx) => (
                  <div key={plan.id} onClick={() => setEditingPlanId(idx)} className="bg-white p-5 rounded-2xl border border-slate-100 flex justify-between items-center active:scale-[0.98] transition-all shadow-sm">
                      <div><h3 className="font-bold text-lg text-slate-800">{plan.name}</h3><p className="text-sm text-slate-400 mt-1">{plan.exercises.length} 个动作</p></div>
                      <div className="w-10 h-10 bg-slate-50 rounded-full flex items-center justify-center text-slate-400"><Edit3 size={18} /></div>
                  </div>
                ))}</div>
                <div className="pt-8 border-t border-slate-100">
                  <h3 className="font-bold text-slate-800 mb-4">数据安全</h3>
                  <div className="grid grid-cols-2 gap-3 mb-4">
                      <button onClick={exportData} className="flex items-center justify-center gap-2 p-4 bg-blue-50 text-blue-600 rounded-2xl font-bold hover:bg-blue-100 transition-colors active:scale-95"><Download size={20}/> 备份数据</button>
                      <button onClick={() => fileRef.current.click()} className="flex items-center justify-center gap-2 p-4 bg-green-50 text-green-600 rounded-2xl font-bold hover:bg-green-100 transition-colors active:scale-95"><Upload size={20}/> 恢复数据</button>
                      <input type="file" ref={fileRef} style={{display:'none'}} accept=".json" onChange={handleFileImport} />
                  </div>
                  <button onClick={() => { if(window.confirm('确定要清空所有历史记录吗？此操作不可恢复！')) { localStorage.clear(); window.location.reload(); } }} className="w-full py-4 text-red-400 font-bold text-sm hover:bg-red-50 rounded-xl transition-colors">⚠ 重置所有数据</button>
                </div>
            </div>
          ) : (
             <div className="space-y-4 pb-20">
                 <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm"><label className="text-xs font-bold text-slate-400 block mb-2 uppercase tracking-wider">计划名称</label><input value={plans[editingPlanId].name} onChange={(e) => updatePlanName(editingPlanId, e.target.value)} className="w-full text-xl font-black bg-transparent border-b-2 border-slate-100 pb-2 outline-none focus:border-orange-500 transition-colors" /></div>
                 {plans[editingPlanId].exercises.map((ex, exIdx) => (
                     <div key={ex.id} className="bg-white p-5 rounded-2xl border border-slate-100 relative group shadow-sm">
                         <button onClick={() => deleteExercise(editingPlanId, ex.id)} className="absolute top-3 right-3 p-2 text-slate-300 hover:text-red-500 transition-colors"><X size={18}/></button>
                         <div className="grid grid-cols-12 gap-3 items-end">
                             <div className="col-span-12 mb-2"><label className="text-[10px] font-bold text-slate-400 uppercase">动作名称</label><input value={ex.name} onChange={(e) => updateExercise(editingPlanId, exIdx, 'name', e.target.value)} className="w-full font-bold text-slate-800 bg-slate-50 p-3 rounded-xl mt-1 focus:ring-2 ring-orange-100 outline-none" /></div>
                             <div className="col-span-4"><label className="text-[10px] font-bold text-slate-400 uppercase">组数</label><input type="number" value={ex.sets} onChange={(e) => updateExercise(editingPlanId, exIdx, 'sets', parseInt(e.target.value))} className="w-full bg-slate-50 p-2 rounded-lg text-center font-bold" /></div>
                             <div className="col-span-4"><label className="text-[10px] font-bold text-slate-400 uppercase">目标</label><input value={ex.defaultReps} onChange={(e) => updateExercise(editingPlanId, exIdx, 'defaultReps', e.target.value)} className="w-full bg-slate-50 p-2 rounded-lg text-center font-bold" /></div>
                             <div className="col-span-4"><label className="text-[10px] font-bold text-slate-400 uppercase">类型</label><select value={ex.unit} onChange={(e) => updateExercise(editingPlanId, exIdx, 'unit', e.target.value)} className="w-full bg-slate-50 p-2 rounded-lg text-xs font-bold appearance-none text-center"><option value="weight_reps">负重</option><option value="reps_only">自重</option><option value="time">计时</option></select></div>
                         </div>
                     </div>
                 ))}
                 <button onClick={() => addExercise(editingPlanId)} className="w-full py-4 border-2 border-dashed border-slate-300 rounded-2xl text-slate-400 font-bold hover:bg-slate-50 hover:text-slate-500 hover:border-slate-400 flex items-center justify-center gap-2 transition-all"><Plus size={20} /> 添加动作</button>
             </div>
          )}
      </div>
  );

  return (
    <div className="max-w-md mx-auto h-screen bg-slate-50 dark:bg-slate-950 flex flex-col font-sans overflow-hidden selection:bg-orange-100">
      {activeTab !== 'workout' && <header className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-6 py-4 flex justify-between items-center sticky top-0 z-10 safe-top"><h1 className="text-xl font-black italic text-slate-900 dark:text-white tracking-tighter">劳大壮<span className="text-orange-500">养成记</span></h1></header>}
      <main className="flex-1 overflow-y-auto p-4 pb-24 no-scrollbar">
        {activeTab === 'home' && renderHomeView()}
        {activeTab === 'workout' && renderWorkoutView()}
        {activeTab === 'stats' && renderStatsView()}
        {activeTab === 'settings' && renderSettingsView()}
      </main>
      {activeTab !== 'workout' && <nav className="bg-white/90 dark:bg-slate-900/90 backdrop-blur-lg border-t border-slate-200 dark:border-slate-800 fixed bottom-0 w-full max-w-md flex justify-around py-4 pb-6 z-20 shadow-[0_-5px_10px_rgba(0,0,0,0.02)] safe-bottom">
          <button onClick={() => setActiveTab('home')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'home' ? 'text-orange-500' : 'text-slate-400'}`}><Activity size={24} strokeWidth={activeTab === 'home' ? 2.5 : 2} /></button>
          <button onClick={() => setActiveTab('stats')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'stats' ? 'text-orange-500' : 'text-slate-400'}`}><BarChart3 size={24} strokeWidth={activeTab === 'stats' ? 2.5 : 2} /></button>
          <button onClick={() => setActiveTab('settings')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'settings' ? 'text-orange-500' : 'text-slate-400'}`}><Settings size={24} strokeWidth={activeTab === 'settings' ? 2.5 : 2} /></button>
        </nav>}
    </div>
  );

